args:
$stamp = Get-Date -Format 'yyyyMMdd_HHmmss';
$dir = '.reports';
New-Item -ItemType Directory -Force -Path $dir | Out-Null;
$out = Join-Path $dir "panel-host-usage-$stamp.txt";
$pattern = 'from\s+["''].*[/\\]panel\.js["'']|\bpanel\.mount\(|\bpanel\.create\(|\bpanel\.drag\.|\bframe\.mount\(|\bframe\.create\(|\bframe\.drag\.';
Get-ChildItem -Path src -Recurse -File -Include *.js |
  Select-String -Pattern $pattern |
  ForEach-Object { "$($_.Path):$($_.LineNumber): $($_.Line.Trim())" } |
  Set-Content -Encoding UTF8 -Path $out;
Write-Host $out;

$label = @'
${input:auditLabel}
'@.Trim();
if ([string]::IsNullOrWhiteSpace($label)) { $label = 'search'; }
$slug = ($label -replace '[^A-Za-z0-9._-]+', '-').Trim('-');
if ([string]::IsNullOrWhiteSpace($slug)) { $slug = 'search'; }
$pattern = @'
${input:auditPattern}
'@;
$rawPaths = @'
${input:auditPaths}
'@;
$rawIncludes = @'
${input:auditIncludes}
'@;
$stamp = Get-Date -Format 'yyyyMMdd_HHmmss';
$dir = '.reports';
New-Item -ItemType Directory -Force -Path $dir | Out-Null;
$out = Join-Path $dir "$slug-$stamp.txt";
$paths = $rawPaths -split '[,;\r\n]+' | ForEach-Object { $_.Trim().Trim('"').Trim("'") } | Where-Object { $_ };
if (!$paths -or $paths.Count -eq 0) { $paths = @('src'); }
$includes = $rawIncludes -split '[,;\r\n]+' | ForEach-Object { $_.Trim().Trim('"').Trim("'") } | Where-Object { $_ };
if (!$includes -or $includes.Count -eq 0) { $includes = @('*.js'); }
$header = @(
  "audit: $label",
  "created: $stamp",
  "paths: $($paths -join ', ')",
  "includes: $($includes -join ', ')",
  "pattern: $pattern",
  ""
);
$header | Set-Content -Encoding UTF8 -Path $out;
Get-ChildItem -Path $paths -Recurse -File -Include $includes -ErrorAction SilentlyContinue |
  Select-String -Pattern $pattern |
  ForEach-Object { "$($_.Path):$($_.LineNumber): $($_.Line.Trim())" } |
  Add-Content -Encoding UTF8 -Path $out;
Write-Host $out;

$raw = '${input:handoffFiles}';
$label = '${input:handoffLabel}';
if ([string]::IsNullOrWhiteSpace($label)) { $label = 'files'; }
$slug = ($label -replace '[^A-Za-z0-9._-]+', '-').Trim('-');
if ([string]::IsNullOrWhiteSpace($slug)) { $slug = 'files'; }
$stamp = Get-Date -Format 'yyyyMMdd_HHmmss';
$root = '.handoff';
$stage = Join-Path $root "$slug-$stamp";
New-Item -ItemType Directory -Force -Path $stage | Out-Null;
$manifest = Join-Path $stage 'MANIFEST.txt';
$paths = $raw -split '[,;\r\n]+' | ForEach-Object { $_.Trim().Trim('"').Trim("'") } | Where-Object { $_ };
"handoff: $label" | Set-Content -Encoding UTF8 -Path $manifest;
"created: $stamp" | Add-Content -Encoding UTF8 -Path $manifest;
"" | Add-Content -Encoding UTF8 -Path $manifest;
foreach ($file in $paths) {
  $normalized = $file -replace '\\', '/';
  if (!(Test-Path -LiteralPath $normalized -PathType Leaf)) {
    "MISSING`t$normalized" | Add-Content -Encoding UTF8 -Path $manifest;
    continue;
  }
  $dest = Join-Path $stage $normalized;
  $destDir = Split-Path -Parent $dest;
  if (![string]::IsNullOrWhiteSpace($destDir)) {
    New-Item -ItemType Directory -Force -Path $destDir | Out-Null;
  }
  Copy-Item -LiteralPath $normalized -Destination $dest -Force;
  "OK`t$normalized" | Add-Content -Encoding UTF8 -Path $manifest;
}
$zip = Join-Path $root "$slug-$stamp.zip";
Compress-Archive -Path (Join-Path $stage '*') -DestinationPath $zip -Force;
Write-Host $zip;

$request = @'
${input:assistantRequest}
'@.Trim();
if ([string]::IsNullOrWhiteSpace($request)) {
  Write-Error 'assistant request is empty';
  exit 1;
}
function Split-ValueList($value, $fallback) {
  $raw = [string]$value;
  $items = $raw -split '[,\r\n]+' | ForEach-Object { $_.Trim().Trim('"').Trim("'") } | Where-Object { $_ };
  if (!$items -or $items.Count -eq 0) { return @($fallback); }
  return @($items);
}
function Slug($value, $fallback) {
  $raw = [string]$value;
  if ([string]::IsNullOrWhiteSpace($raw)) { $raw = $fallback; }
  $slug = ($raw -replace '[^A-Za-z0-9._-]+', '-').Trim('-');
  if ([string]::IsNullOrWhiteSpace($slug)) { $slug = $fallback; }
  return $slug;
}
function ValueOr($map, $key, $fallback) {
  if ($map.ContainsKey($key)) {
    $value = [string]$map[$key];
    if (![string]::IsNullOrWhiteSpace($value)) { return $value; }
  }
  return $fallback;
}
$data = @{};
$parts = $request -split '\s*;;;\s*';
foreach ($part in $parts) {
  if ($part -match '^\s*([^=:]+?)\s*[:=]\s*([\s\S]*)$') {
    $key = $matches[1].Trim().ToLowerInvariant();
    $value = $matches[2].Trim();
    if (![string]::IsNullOrWhiteSpace($key)) { $data[$key] = $value; }
  }
}
$mode = (ValueOr $data 'mode' 'handoff').Trim().ToLowerInvariant();
$label = ValueOr $data 'label' $mode;
$slug = Slug $label $mode;
$stamp = Get-Date -Format 'yyyyMMdd_HHmmss';
if ($mode -eq 'audit' -or $mode -eq 'search') {
  $paths = Split-ValueList (ValueOr $data 'paths' 'src') 'src';
  $includes = Split-ValueList (ValueOr $data 'includes' '*.js') '*.js';
  $pattern = ValueOr $data 'pattern' '';
  if ([string]::IsNullOrWhiteSpace($pattern)) {
    Write-Error 'audit request requires pattern=...';
    exit 1;
  }
  $dir = '.reports';
  New-Item -ItemType Directory -Force -Path $dir | Out-Null;
  $out = Join-Path $dir "$slug-$stamp.txt";
  @(
    "audit: $label",
    "created: $stamp",
    "paths: $($paths -join ', ')",
    "includes: $($includes -join ', ')",
    "pattern: $pattern",
    ""
  ) | Set-Content -Encoding UTF8 -Path $out;
  Get-ChildItem -Path $paths -Recurse -File -Include $includes -ErrorAction SilentlyContinue |
    Select-String -Pattern $pattern |
    ForEach-Object { "$($_.Path):$($_.LineNumber): $($_.Line.Trim())" } |
    Add-Content -Encoding UTF8 -Path $out;
  Write-Host $out;
  exit 0;
}
if ($mode -eq 'handoff' -or $mode -eq 'files') {
  $filesRaw = ValueOr $data 'files' '';
  if ([string]::IsNullOrWhiteSpace($filesRaw)) {
    $filesRaw = ValueOr $data 'paths' '';
  }
  $files = $filesRaw -split '[,\r\n]+' | ForEach-Object { $_.Trim().Trim('"').Trim("'") } | Where-Object { $_ };
  if (!$files -or $files.Count -eq 0) {
    Write-Error 'handoff request requires files=...';
    exit 1;
  }
  $root = '.handoff';
  $stage = Join-Path $root "$slug-$stamp";
  New-Item -ItemType Directory -Force -Path $stage | Out-Null;
  $manifest = Join-Path $stage 'MANIFEST.txt';
  @("handoff: $label", "created: $stamp", "") | Set-Content -Encoding UTF8 -Path $manifest;
  foreach ($file in $files) {
    $normalized = $file -replace '\\', '/';
    if (!(Test-Path -LiteralPath $normalized -PathType Leaf)) {
      "MISSING`t$normalized" | Add-Content -Encoding UTF8 -Path $manifest;
      continue;
    }
    $dest = Join-Path $stage $normalized;
    $destDir = Split-Path -Parent $dest;
    if (![string]::IsNullOrWhiteSpace($destDir)) {
      New-Item -ItemType Directory -Force -Path $destDir | Out-Null;
    }
    Copy-Item -LiteralPath $normalized -Destination $dest -Force;
    "OK`t$normalized" | Add-Content -Encoding UTF8 -Path $manifest;
  }
  $zip = Join-Path $root "$slug-$stamp.zip";
  Compress-Archive -Path (Join-Path $stage '*') -DestinationPath $zip -Force;
  Write-Host $zip;
  exit 0;
}
Write-Error "unknown mode: $mode";
exit 1;
